function estimateSheetBuildRowsFromSpec(type) {
  const spec = window.ESTIMATE_EXCEL_TEMPLATE_SPECS?.[type] || window.ESTIMATE_EXCEL_TEMPLATE_SPECS?.[estimateSheetActiveType];
  const rows = Array.from({ length: spec?.maxRow || 0 }, () => Array.from({ length: spec?.maxCol || 0 }, () => ""));
  (spec?.cells || []).forEach(cell => {
    if (rows[cell.r - 1]) rows[cell.r - 1][cell.c - 1] = estimateSheetCellText(cell.v);
  });
  return rows;
}

function cloneEstimateSheetRows(type) {
  return estimateSheetBuildRowsFromSpec(type || estimateSheetActiveType);
}

function estimateSheetGetSpec() {
  return window.ESTIMATE_EXCEL_TEMPLATE_SPECS?.[estimateSheetActiveType] || window.ESTIMATE_EXCEL_TEMPLATE_SPECS?.["개산견적"];
}

function estimateSheetCellValueFromRows(rows, r, c, fallback) {
  const v = rows?.[r - 1]?.[c - 1];
  return v === undefined || v === null ? estimateSheetCellText(fallback) : estimateSheetCellText(v);
}

function estimateSheetRenderInlineStyle(style) {
  return style ? ` style="${String(style).replace(/"/g, '&quot;')}"` : "";
}

function estimateSheetImagePosition(spec, img) {
  const colLeft = (col) => spec.cols.slice(0, Math.max(0, col - 1)).reduce((a, b) => a + Number(b || 0), 0);
  const rowTop = (row) => spec.rows.slice(0, Math.max(0, row - 1)).reduce((a, b) => a + Number(b || 0), 0);
  const left = colLeft(img.from.col) + ((img.from.colOff || 0) / 9525);
  const top = rowTop(img.from.row) + ((img.from.rowOff || 0) / 9525);
  const right = colLeft(img.to.col) + ((img.to.colOff || 0) / 9525);
  const bottom = rowTop(img.to.row) + ((img.to.rowOff || 0) / 9525);
  return { left, top, width: Math.max(10, right - left), height: Math.max(10, bottom - top) };
}

function renderEstimateSheetGrid() {
  const grid = document.getElementById("estimateSheetGrid");
  if (!grid) return;
  const spec = estimateSheetGetSpec();
  if (!spec) return;
  if (!estimateSheetEditorRows) estimateSheetEditorRows = cloneEstimateSheetRows(estimateSheetActiveType);

  const mergeSkip = new Set();
  const cellMap = new Map();
  (spec.cells || []).forEach(cell => {
    cellMap.set(`${cell.r}:${cell.c}`, cell);
    const rs = Number(cell.rs || 1);
    const cs = Number(cell.cs || 1);
    for (let rr = cell.r; rr < cell.r + rs; rr += 1) {
      for (let cc = cell.c; cc < cell.c + cs; cc += 1) {
        if (rr !== cell.r || cc !== cell.c) mergeSkip.add(`${rr}:${cc}`);
      }
    }
  });

  const colHeaders = Array.from({ length: spec.maxCol }, (_, i) => `<th class="estimate-excel-col-head" style="width:${spec.cols[i]}px;min-width:${spec.cols[i]}px;max-width:${spec.cols[i]}px;">${estimateSheetColumnLabel(i)}</th>`).join("");
  const colGroup = `<colgroup><col style="width:40px;min-width:40px;max-width:40px;">${(spec.cols || []).map(w => `<col style="width:${w}px;min-width:${w}px;max-width:${w}px;">`).join("")}</colgroup>`;

  const bodyRows = Array.from({ length: spec.maxRow }, (_, rIdx) => {
    const r = rIdx + 1;
    const height = spec.rows[rIdx] || 20;
    const cells = Array.from({ length: spec.maxCol }, (_, cIdx) => {
      const c = cIdx + 1;
      if (mergeSkip.has(`${r}:${c}`)) return "";
      const base = cellMap.get(`${r}:${c}`) || { r, c, v: "", rs: 1, cs: 1, s: "" };
      const value = estimateSheetCellValueFromRows(estimateSheetEditorRows, r, c, base.v);
      const cls = ["estimate-excel-cell"];
      if (c > (spec.printCols || 7)) cls.push("outside-print");
      if (c === 1) cls.push("print-left");
      if (c === (spec.printCols || 7)) cls.push("print-right");
      if (r === 1) cls.push("print-top");
      if (r === spec.maxRow) cls.push("print-bottom");
      if (!value) cls.push("blank-cell");
      const attrs = [
        `class="${cls.join(" ")}"`,
        `data-row="${r - 1}"`,
        `data-col="${c - 1}"`,
        `contenteditable="true"`,
        `oninput="updateEstimateSheetCell(this)"`
      ];
      if (Number(base.rs || 1) > 1) attrs.push(`rowspan="${base.rs}"`);
      if (Number(base.cs || 1) > 1) attrs.push(`colspan="${base.cs}"`);
      return `<td ${attrs.join(" ")}${estimateSheetRenderInlineStyle(base.s)}>${estimateSheetHtml(value)}</td>`;
    }).join("");
    return `<tr style="height:${height}px;"><th class="estimate-excel-row-head" style="height:${height}px;">${r}</th>${cells}</tr>`;
  }).join("");

  grid.className = "estimate-sheet-grid estimate-excel-grid";
  grid.innerHTML = `${colGroup}<thead><tr><th class="estimate-excel-corner"></th>${colHeaders}</tr></thead><tbody>${bodyRows}</tbody>`;

  const wrap = grid.closest(".estimate-sheet-grid-wrap");
  if (wrap) {
    wrap.classList.add("estimate-excel-grid-wrap");
    wrap.querySelectorAll(".estimate-excel-image").forEach(node => node.remove());
    const tableLeft = 40;
    const headerTop = 28;
    (spec.images || []).forEach((img, i) => {
      const pos = estimateSheetImagePosition(spec, img);
      const image = document.createElement("img");
      image.className = "estimate-excel-image";
      image.src = img.data;
      image.alt = `견적서 이미지 ${i + 1}`;
      image.style.left = `${tableLeft + pos.left}px`;
      image.style.top = `${headerTop + pos.top}px`;
      image.style.width = `${pos.width}px`;
      image.style.height = `${pos.height}px`;
      wrap.appendChild(image);
    });
  }
}

function openEstimateSheetEditor(index = null) {
  const editor = document.getElementById("estimateSheetEditor");
  if (!editor) return;
  if (index !== null && estimateSheetRecords[index]) {
    estimateSheetEditingIndex = index;
    estimateSheetActiveType = estimateSheetRecords[index].type || estimateSheetActiveType;
    estimateSheetEditorRows = JSON.parse(JSON.stringify(estimateSheetRecords[index].rows || cloneEstimateSheetRows(estimateSheetActiveType)));
  } else {
    estimateSheetEditingIndex = null;
    estimateSheetEditorRows = cloneEstimateSheetRows(estimateSheetActiveType);
  }
  editor.classList.remove("hidden");
  const spec = estimateSheetGetSpec();
  const titleNode = document.getElementById("estimateSheetEditorTitle");
  const subNode = document.getElementById("estimateSheetEditorSub");
  if (titleNode) titleNode.textContent = `${estimateSheetActiveType} 견적서 작성`;
  if (subNode) subNode.textContent = `${spec?.name || "업로드 엑셀"} 원본 양식 기준 · 행/열/병합/테두리/색상 반영`;
  renderEstimateSheetManage();
  renderEstimateSheetGrid();
  editor.scrollIntoView({ behavior: "smooth", block: "start" });
}

function resetEstimateSheetEditor() {
  estimateSheetEditorRows = cloneEstimateSheetRows(estimateSheetActiveType);
  renderEstimateSheetGrid();
  if (typeof showToast === "function") showToast("업로드된 원본 엑셀 양식으로 초기화했습니다.");
}

function exportEstimateSheetCurrentHtml() {
  const spec = estimateSheetGetSpec();
  if (!spec?.xlsx) return;
  const bytes = atob(spec.xlsx);
  const arr = new Uint8Array(bytes.length);
  for (let i = 0; i < bytes.length; i += 1) arr[i] = bytes.charCodeAt(i);
  const blob = new Blob([arr], { type: "application/vnd.openxmlformats-officedocument.spreadsheetml.sheet" });
  const url = URL.createObjectURL(blob);
  const a = document.createElement("a");
  const safeType = String(estimateSheetActiveType || "견적서").replace(/[\\/:*?"<>|]/g, "_");
  a.href = url;
  a.download = `CONCOST_${safeType}_원본양식.xlsx`;
  document.body.appendChild(a);
  a.click();
  a.remove();
  URL.revokeObjectURL(url);
  if (typeof showToast === "function") showToast("업로드한 원본 엑셀 양식을 그대로 내려받았습니다.");
}

function setEstimateSheetType(type) {
  estimateSheetActiveType = type;
  document.querySelectorAll(".estimate-sheet-tab").forEach(btn => {
    btn.classList.toggle("active", btn.dataset.sheetType === type);
  });
  closeEstimateSheetEditor();
  renderEstimateSheetList();
}

function getEstimateSheetRecordSummary(record) {
  const rows = record?.rows || cloneEstimateSheetRows(record?.type || estimateSheetActiveType);
  return {
    recipient: getEstimateSheetCell(rows, 4, 1) || "-",
    project: getEstimateSheetCell(rows, 5, 1) || "-",
    service: getEstimateSheetCell(rows, 6, 1) || "-",
    total: getEstimateSheetCell(rows, 9, 1) || "-"
  };
}

document.addEventListener("DOMContentLoaded", () => {
  estimateSheetActiveType = estimateSheetActiveType || "개산견적";
  renderEstimateSheetManage?.();
});


